#include <bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
int quickpow(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)ans=ans*a;
        a=a*a;
		b>>=1;
	}
	return ans;
}

CI MAXN=1e3+5;
vector<PII> g[MAXN];
int n,q,f[MAXN][MAXN];
void dfs(int u, int fa)
{
	FOI(s,g[u])
	{
		int v=s.fst,w=s.snd;
		if(v==fa)continue;
		dfs(v,u);
		ROF(j,q,1)
		{
			FOR(k,0,j-1)
			{
				f[u][j]=max(f[u][j],f[u][j-1-k]+f[v][k]+w);
			}
		}
	}
}
signed main(void)
{
    //freopen(".in","r",stdin);
    //freopen(".out","w",stdout);
	ios::sync_with_stdio(0);
	cin.tie(0);
	cout.tie(0);
	cin>>n>>q;
	FOR(i,2,n)
	{
		int u,v,w;
		cin>>u>>v>>w;
		g[u].pb(mk(v,w));
		g[v].pb(mk(u,w));
	}
	dfs(1,1);
	cout<<f[1][q];
	return false;
}
